CREATE TABLE IF NOT EXISTS curriculos (id SERIAL PRIMARY KEY, nome VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL UNIQUE, telefone VARCHAR(50), linkedin VARCHAR(255), cargo_desejado VARCHAR(255), area_atuacao VARCHAR(255), nivel_experiencia VARCHAR(50), pretensao_salarial DECIMAL(10, 2), disponibilidade VARCHAR(50), resumo_profissional TEXT, habilidades TEXT[], arquivo_curriculo VARCHAR(500), status VARCHAR(50) DEFAULT 'novo', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
